var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"무슨 일이죠. 부회장? 다들 캠프파이어 준비 때문에 바쁜 것 같은데.","JPN":"どうかしたんですか、副会長？\\nみんなキャンプファイヤーの準備で忙しいのでは？","ENG":"You wanted to see me, Lelouch? Looks like the others are all busy with the campfire preparations.","TWN":"副會長？有什麼事嗎？大家都忙著準備營火呢。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"훗, 너는 언제까지 이런 연극을 계속할 생각이지?","JPN":"ふっ。お前はいつまでそんな空々しい芝居を続けるつもりだ？","ENG":"Hah, how much longer are you going to keep up with that act?","TWN":"呵，你要演到什麼時候？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"너의 그 뻔한 연극은 이미 눈치채고 있었다, 라고 말한거다.","JPN":"お前のそのくだらない芝居には気づいている、と言ったんだ。","ENG":"I'm telling you that I see through your poor acting skills.","TWN":"我早就已經識破你的癟腳演技。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그리고 네가 이 연극의 각본가라는 것도 이미 알고 있지.","JPN":"そしてお前がこの芝居の脚本家だということもな。","ENG":"And I also know that you are the writer of this little play.","TWN":"而且我還知道你就是這齣鬧劇的編劇。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"각본가? 무슨 말을 하고 싶은 거죠?","JPN":"脚本家？　何が言いたいのですか？","ENG":"Writer? I don't understand what you're trying to say.","TWN":"編劇？你想說什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하고 싶은 말? 내가 하고 싶은 말은 하나 뿐이야.","JPN":"言いたいこと、か？　そうだな。言いたいことは一つだけだ。","ENG":"What I'm trying to say? There's only one thing I want to say to you.","TWN":"我想說什麼？我想說的只有一件事。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"를르슈 비 브리타니아가 명한다.","JPN":"ルルーシュ・ヴィ・ブリタニアが命じる。","ENG":"I, Lelouch vi Britannia, command you.","TWN":"魯路修·Vi·不列顛尼亞在此命令。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"너는……","JPN":"お前は……","ENG":"To...","TWN":"你……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"<color=#ff3636>죽어라.</color>","JPN":"<color=#ff3636>死ね。</color>","ENG":"<color=#ff3636>Die.</color>","TWN":"<color=#ff3636>去死。</color>"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"},{"id":"L17_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"훗, 갑자기 죽으라니 말이 심하시네요.","JPN":"ふっ。「死ね」だなんて、酷いことを言う。","ENG":"Ha, \\"Die?\\" Don't you think that's a bit extreme?","TWN":"呵，怎麼突然叫我去死，這麼過分。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L19_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"역시 기아스는 듣지 않는군. 하지만 그것이야 말로 확실한 증거다. 그럼 이건 어때?","JPN":"やはりギアスが効かないか。\\nしかし、それが何よりの証拠だ。なら、これでどうだ？","ENG":"So my Geass doesn't work on you. But that in itself is irrefutable proof. Then, how's this?!","TWN":"果然不受Geass控制，不過這就是千真萬確的證據。那這個怎麼樣？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"무, 무슨……!?","JPN":"な、何を……！？","ENG":"W-what the...?!","TWN":"什，什麼……！？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"예상하고 있었지만, 실제로 보니 더 놀랍군.","JPN":"予想はしていたが、実際に見てみると驚かされるな。","ENG":"As I expected, but it is still surprising to see it in person.","TWN":"雖然我有做好心理準備，但實際看到後更驚人呢。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"기아스가 듣지 않았던 이유는…… ","JPN":"ギアスが効かなかった理由は……、","ENG":"The reason my Geass doesn't work on you is... ","TWN":"不受Geass控制的理由…… "},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사람이 아니라 기계 몸이었기 때문이었나.","JPN":"人間ではない、機械の身体だからか。","ENG":"Because you're a robot and not human, right?","TWN":"是因為你不是人，而是機器嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"……타피르?","JPN":"……タピル。","ENG":"...Tapir?","TWN":"……達爾？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};